{
  "name": "JyotishAI - Vedic Kundali & Horoscope",
  "description": "A comprehensive Vedic Astrology app for personalized Kundali, accurate horoscope predictions (Daily, Weekly, Monthly), and Ashtakoot Matchmaking powered by Gemini AI.",
  "requestFramePermissions": [
    "geolocation"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface BirthDetails {
  name: string;
  dob: string;
  tob: string;
  location: string;
  latitude?: number;
  longitude?: number;
}

export interface MatchmakingDetails {
  boy: BirthDetails;
  girl: BirthDetails;
}

export type MoonSign = 
  | 'Aries' | 'Taurus' | 'Gemini' | 'Cancer' 
  | 'Leo' | 'Virgo' | 'Libra' | 'Scorpio' 
  | 'Sagittarius' | 'Capricorn' | 'Aquarius' | 'Pisces';

export type Timeframe = 'daily' | 'weekly' | 'monthly';

export interface PredictionResult {
  overview: string;
  career: string;
  health: string;
  relationships: string;
  finance: string;
  spirituality: string;
  luckyColor: string;
  luckyNumber: string;
}

export interface KundaliAnalysis {
  chartData: string; // Base64 or Description
  planetsPositions: string;
  detailedAnalysis: string;
  remedies: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { BirthDetails, MatchmakingDetails, MoonSign, Timeframe } from "../types";

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getCoordinates = async (location: string) => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash',
    contents: `Find the precise latitude and longitude for birth place: "${location}". Return ONLY JSON format.`,
    config: {
      tools: [{ googleMaps: {} }],
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          lat: { type: Type.NUMBER },
          lng: { type: Type.NUMBER },
          formattedAddress: { type: Type.STRING }
        },
        required: ["lat", "lng"]
      }
    }
  });

  try {
    return JSON.parse(response.text);
  } catch (e) {
    console.error("Failed to parse coordinates", e);
    return { lat: 0, lng: 0, formattedAddress: location };
  }
};

export const getHoroscope = async (sign: string, timeframe: Timeframe) => {
  const ai = getAI();
  const prompt = `As a professional Vedic Astrologer, provide a highly detailed and precise ${timeframe} prediction for the Moon Sign (Rashi) ${sign}. 
  Cover every important aspect: Overview, Career, Health, Relationships, Finance, Spirituality, Lucky Color, and Lucky Number. 
  Ensure the tone is authentic, mystical yet practical.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      thinkingConfig: { thinkingBudget: 5000 },
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          overview: { type: Type.STRING },
          career: { type: Type.STRING },
          health: { type: Type.STRING },
          relationships: { type: Type.STRING },
          finance: { type: Type.STRING },
          spirituality: { type: Type.STRING },
          luckyColor: { type: Type.STRING },
          luckyNumber: { type: Type.STRING },
        }
      }
    }
  });

  return JSON.parse(response.text);
};

export const getKundaliAnalysis = async (details: BirthDetails) => {
  const ai = getAI();
  const prompt = `Generate a detailed Vedic Kundali analysis for:
  Name: ${details.name}
  DOB: ${details.dob}
  Time: ${details.tob}
  Location: ${details.location} (Lat: ${details.latitude}, Lng: ${details.longitude})

  Provide:
  1. Detailed planet positions in various houses.
  2. Character Analysis based on Ascendant and Moon Sign.
  3. Major Dashas and upcoming periods.
  4. Precise life predictions for Career, Marriage, and Wealth.
  5. Specific Vedic remedies (Mantras, Gemstones).
  6. ASCII/Simplified visual representation description of the Lagna Chart (North Indian style).`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: prompt,
    config: {
      thinkingConfig: { thinkingBudget: 15000 }
    }
  });

  return response.text;
};

export const getMatchmaking = async (details: MatchmakingDetails) => {
  const ai = getAI();
  const prompt = `Perform a traditional Vedic Ashtakoot Milan (36 Gunas) for matchmaking:
  Person 1 (Boy): ${details.boy.name}, ${details.boy.dob}, ${details.boy.tob}, ${details.boy.location}
  Person 2 (Girl): ${details.girl.name}, ${details.girl.dob}, ${details.girl.tob}, ${details.girl.location}

  Calculate the gunas (Varna, Vashya, Tara, Yoni, Maitri, Gana, Bhakoot, Nadi).
  Explain the compatibility score and detailed analysis of their life together (Financial, Emotional, Family).
  Note any Doshas like Manglik Dosha compatibility.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: prompt,
    config: {
      thinkingConfig: { thinkingBudget: 15000 }
    }
  });

  return response.text;
};

