import React, { useState, useEffect } from 'react';
import { ZODIAC_SIGNS } from '../constants';
import { Timeframe, PredictionResult } from '../types';
import { getHoroscope } from '../services/geminiService';

const HoroscopeView: React.FC = () => {
  const [selectedSign, setSelectedSign] = useState(ZODIAC_SIGNS[0].name);
  const [timeframe, setTimeframe] = useState<Timeframe>('daily');
  const [loading, setLoading] = useState(false);
  const [prediction, setPrediction] = useState<PredictionResult | null>(null);

  const fetchHoroscope = async () => {
    setLoading(true);
    try {
      const data = await getHoroscope(selectedSign, timeframe);
      setPrediction(data);
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchHoroscope();
  }, [selectedSign, timeframe]);

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      {/* Sign Grid */}
      <div className="grid grid-cols-3 sm:grid-cols-4 md:grid-cols-6 gap-3">
        {ZODIAC_SIGNS.map((sign) => (
          <button
            key={sign.name}
            onClick={() => setSelectedSign(sign.name)}
            className={`flex flex-col items-center p-3 rounded-xl border transition-all ${
              selectedSign === sign.name
                ? 'bg-amber-600/20 border-amber-500 shadow-[0_0_15px_rgba(245,158,11,0.2)]'
                : 'bg-slate-800/40 border-slate-700 hover:border-slate-500'
            }`}
          >
            <span className="text-3xl mb-1">{sign.symbol}</span>
            <span className="text-xs font-semibold uppercase tracking-wider text-slate-300">{sign.name}</span>
            <span className="text-[10px] text-slate-500 italic">{sign.moonSign}</span>
          </button>
        ))}
      </div>

      {/* Timeframe Toggles */}
      <div className="flex justify-center gap-2">
        {(['daily', 'weekly', 'monthly'] as Timeframe[]).map((tf) => (
          <button
            key={tf}
            onClick={() => setTimeframe(tf)}
            className={`px-6 py-2 rounded-full text-sm font-medium border capitalize transition-all ${
              timeframe === tf
                ? 'bg-slate-200 text-slate-900 border-white'
                : 'bg-transparent text-slate-400 border-slate-700 hover:border-slate-500'
            }`}
          >
            {tf}
          </button>
        ))}
      </div>

      {/* Prediction Display */}
      {loading ? (
        <div className="flex flex-col items-center justify-center py-20 space-y-4">
          <div className="w-12 h-12 border-4 border-amber-500/30 border-t-amber-500 rounded-full animate-spin"></div>
          <p className="text-slate-400 font-cinzel">Consulting the celestial bodies...</p>
        </div>
      ) : prediction ? (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="col-span-1 md:col-span-2 bg-slate-800/50 p-6 rounded-2xl border border-slate-700 shadow-xl">
            <h3 className="text-xl font-cinzel text-amber-400 mb-3 flex items-center gap-2">
              <span>✨</span> Overview
            </h3>
            <p className="text-slate-300 leading-relaxed text-lg italic">"{prediction.overview}"</p>
          </div>

          <PredictionCard title="💼 Career & Finance" content={prediction.career + " " + prediction.finance} icon="💰" />
          <PredictionCard title="🌿 Health & Wellness" content={prediction.health} icon="🧘" />
          <PredictionCard title="💞 Love & Relations" content={prediction.relationships} icon="💖" />
          <PredictionCard title="✨ Spirituality" content={prediction.spirituality} icon="🕉️" />

          <div className="col-span-1 md:col-span-2 flex flex-wrap gap-4 justify-center bg-amber-900/10 p-4 rounded-xl border border-amber-900/30">
            <div className="flex items-center gap-2">
              <span className="text-slate-400 text-sm">Lucky Color:</span>
              <span className="font-bold text-amber-500">{prediction.luckyColor}</span>
            </div>
            <div className="w-px h-4 bg-slate-700"></div>
            <div className="flex items-center gap-2">
              <span className="text-slate-400 text-sm">Lucky Number:</span>
              <span className="font-bold text-amber-500">{prediction.luckyNumber}</span>
            </div>
          </div>
        </div>
      ) : null}
    </div>
  );
};

const PredictionCard: React.FC<{ title: string; content: string; icon: string }> = ({ title, content, icon }) => (
  <div className="bg-slate-800/30 p-5 rounded-2xl border border-slate-800 hover:border-slate-700 transition-colors">
    <h3 className="text-lg font-cinzel text-slate-200 mb-3 flex items-center gap-2">
      <span>{icon}</span> {title}
    </h3>
    <p className="text-slate-400 leading-relaxed text-sm">{content}</p>
  </div>
);

export default HoroscopeView;

import React, { useState } from 'react';
import { BirthDetails } from '../types';
import { getCoordinates, getKundaliAnalysis } from '../services/geminiService';
import ReactMarkdown from 'https://esm.sh/react-markdown';

const KundaliView: React.FC = () => {
  const [details, setDetails] = useState<BirthDetails>({
    name: '',
    dob: '',
    tob: '',
    location: '',
  });
  const [loading, setLoading] = useState(false);
  const [analysis, setAnalysis] = useState<string | null>(null);
  const [coords, setCoords] = useState<{ lat: number; lng: number } | null>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    try {
      const locationData = await getCoordinates(details.location);
      const enrichedDetails = {
        ...details,
        latitude: locationData.lat,
        longitude: locationData.lng,
      };
      setCoords({ lat: locationData.lat, lng: locationData.lng });
      const result = await getKundaliAnalysis(enrichedDetails);
      setAnalysis(result);
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="space-y-8 max-w-3xl mx-auto">
      {!analysis && (
        <section className="bg-slate-800/40 p-8 rounded-3xl border border-slate-700 shadow-2xl">
          <div className="mb-8 text-center">
            <h2 className="text-3xl font-cinzel text-amber-400 mb-2">Create Your Janma Kundali</h2>
            <p className="text-slate-400">Enter your precise birth details for accurate planetary positions.</p>
          </div>

          <form onSubmit={handleSubmit} className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-400">Full Name</label>
                <input
                  required
                  type="text"
                  placeholder="e.g. Rahul Sharma"
                  className="w-full bg-slate-900 border border-slate-700 rounded-xl px-4 py-3 focus:ring-2 focus:ring-amber-500 outline-none text-white"
                  value={details.name}
                  onChange={(e) => setDetails({ ...details, name: e.target.value })}
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-400">Birth Location</label>
                <input
                  required
                  type="text"
                  placeholder="e.g. Mumbai, Maharashtra"
                  className="w-full bg-slate-900 border border-slate-700 rounded-xl px-4 py-3 focus:ring-2 focus:ring-amber-500 outline-none text-white"
                  value={details.location}
                  onChange={(e) => setDetails({ ...details, location: e.target.value })}
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-400">Date of Birth</label>
                <input
                  required
                  type="date"
                  className="w-full bg-slate-900 border border-slate-700 rounded-xl px-4 py-3 focus:ring-2 focus:ring-amber-500 outline-none text-white"
                  value={details.dob}
                  onChange={(e) => setDetails({ ...details, dob: e.target.value })}
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-400">Time of Birth</label>
                <input
                  required
                  type="time"
                  className="w-full bg-slate-900 border border-slate-700 rounded-xl px-4 py-3 focus:ring-2 focus:ring-amber-500 outline-none text-white"
                  value={details.tob}
                  onChange={(e) => setDetails({ ...details, tob: e.target.value })}
                />
              </div>
            </div>

            <button
              disabled={loading}
              className="w-full bg-gradient-to-r from-amber-600 to-orange-700 hover:from-amber-500 hover:to-orange-600 text-white font-bold py-4 rounded-xl transition-all shadow-lg shadow-orange-900/20 disabled:opacity-50"
            >
              {loading ? 'Mapping the Stars...' : 'Generate Kundali'}
            </button>
          </form>
        </section>
      )}

      {loading && (
        <div className="flex flex-col items-center justify-center py-20 space-y-6">
          <div className="relative">
            <div className="w-24 h-24 border-4 border-amber-500/10 border-t-amber-500 rounded-full animate-spin"></div>
            <div className="absolute inset-0 flex items-center justify-center text-3xl">✨</div>
          </div>
          <div className="text-center space-y-2">
            <p className="text-xl font-cinzel text-amber-200">Calculating Celestial Positions</p>
            <p className="text-slate-500 text-sm animate-pulse">Computing Lagna, Bhavas, and Dashas...</p>
          </div>
        </div>
      )}

      {analysis && !loading && (
        <div className="space-y-6 animate-in slide-in-from-bottom-10 duration-700">
          <div className="flex justify-between items-center bg-slate-800/50 p-6 rounded-2xl border border-slate-700">
            <div>
              <h2 className="text-2xl font-cinzel text-amber-400">{details.name}'s Chart</h2>
              <p className="text-slate-400 text-sm">{details.dob} | {details.tob} | {details.location}</p>
            </div>
            {coords && (
              <div className="text-right">
                <span className="text-[10px] uppercase text-slate-500 font-bold block">Coordinates</span>
                <span className="text-amber-500 font-mono text-sm">Lat: {coords.lat.toFixed(4)}</span>
