import React, { useState } from 'react';
import Layout from './components/Layout';
import HoroscopeView from './components/HoroscopeView';
import KundaliView from './components/KundaliView';
import MatchmakingView from './components/MatchmakingView';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('horoscope');

  const renderContent = () => {
    switch (activeTab) {
      case 'horoscope':
        return <HoroscopeView />;
      case 'kundali':
        return <KundaliView />;
      case 'matchmaking':
        return <MatchmakingView />;
      default:
        return <HoroscopeView />;
    }
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab}>
      <div className="max-w-5xl mx-auto">
        {renderContent()}
      </div>
    </Layout>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { BirthDetails, MatchmakingDetails, MoonSign, Timeframe } from "../types";

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getCoordinates = async (location: string) => {
  const ai = getAI();
  // We use gemini-3-flash-preview without tools to allow for responseSchema/JSON output.
  // This avoids the conflict where googleMaps tool cannot be used with application/json mime type.
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Find the precise latitude and longitude for the birth place: "${location}". Return the result in JSON format.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          lat: { type: Type.NUMBER, description: "Latitude of the location" },
          lng: { type: Type.NUMBER, description: "Longitude of the location" },
          formattedAddress: { type: Type.STRING, description: "The full formatted address of the location" }
        },
        required: ["lat", "lng", "formattedAddress"]
      }
    }
  });

  try {
    const text = response.text || "{}";
    return JSON.parse(text);
  } catch (e) {
    console.error("Failed to parse coordinates", e);
    return { lat: 0, lng: 0, formattedAddress: location };
  }
};

