import jsPDF from 'jspdf';
import html2canvas from 'html2canvas';

const HoroscopeView: React.FC = () => {
  const [selectedSign, setSelectedSign] = useState(ZODIAC_SIGNS[0].name);
  const [timeframe, setTimeframe] = useState<Timeframe>('daily');
  const [loading, setLoading] = useState(false);
  const [exporting, setExporting] = useState(false);
  const [prediction, setPrediction] = useState<PredictionResult | null>(null);

  const fetchHoroscope = async () => {
    setLoading(true);
    try {
      const data = await getHoroscope(selectedSign, timeframe);
      setPrediction(data);
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchHoroscope();
  }, [selectedSign, timeframe]);

  const downloadPDF = async () => {
    const element = document.getElementById('horoscope-content');
    if (!element || exporting) return;

    setExporting(true);
    try {
      const canvas = await html2canvas(element, {
        scale: 2,
        backgroundColor: '#0f172a',
        useCORS: true,
        logging: false,
        windowWidth: element.scrollWidth,
        windowHeight: element.scrollHeight
      });

      const imgData = canvas.toDataURL('image/png');
      const pdf = new jsPDF('p', 'mm', 'a4');

      const imgProps = pdf.getImageProperties(imgData);
