import React, { useState, useEffect } from 'react';
import { ZODIAC_SIGNS } from '../constants';
import { Timeframe, PredictionResult, Language } from '../types';
import { getHoroscope } from '../services/geminiService';
import jsPDF from 'jspdf';
import html2canvas from 'html2canvas';

interface HoroscopeViewProps {
  language: Language;
}

const HoroscopeView: React.FC<HoroscopeViewProps> = ({ language }) => {
  const [selectedSign, setSelectedSign] = useState(ZODIAC_SIGNS[0].name);
  const [timeframe, setTimeframe] = useState<Timeframe>('daily');
  const [loading, setLoading] = useState(false);
  const [exporting, setExporting] = useState(false);
  const [prediction, setPrediction] = useState<PredictionResult | null>(null);

  const fetchHoroscope = async () => {
    setLoading(true);
    try {
      const data = await getHoroscope(selectedSign, timeframe, language);
      setPrediction(data);
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchHoroscope();
  }, [selectedSign, timeframe, language]);

  const downloadPDF = async () => {
    const element = document.getElementById('horoscope-content');
    if (!element || exporting) return;

    setExporting(true);
    try {
      const canvas = await html2canvas(element, {
        scale: 2,
        backgroundColor: '#0f172a',
        useCORS: true,
        logging: false,
        windowWidth: element.scrollWidth,
        windowHeight: element.scrollHeight
      });

      const imgData = canvas.toDataURL('image/png');
      const pdf = new jsPDF('p', 'mm', 'a4');

      const imgProps = pdf.getImageProperties(imgData);
      const pdfWidth = pdf.internal.pageSize.getWidth();
      const pdfHeight = (imgProps.height * pdfWidth) / imgProps.width;
      const pageHeight = pdf.internal.pageSize.getHeight();

      let heightLeft = pdfHeight;
      let position = 0;

      pdf.addImage(imgData, 'PNG', 0, position, pdfWidth, pdfHeight);
      heightLeft -= pageHeight;

      while (heightLeft >= 0) {
        position = heightLeft - pdfHeight;
        pdf.addPage();
        pdf.addImage(imgData, 'PNG', 0, position, pdfWidth, pdfHeight);
        heightLeft -= pageHeight;
      }

      pdf.save(`Horoscope_${selectedSign}_${timeframe}.pdf`);
    } catch (err) {
      console.error("PDF Export failed", err);
    } finally {
      setExporting(false);
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-12">
      <div className="grid grid-cols-3 sm:grid-cols-4 md:grid-cols-6 gap-3">
        {ZODIAC_SIGNS.map((sign) => (
          <button
            key={sign.name}
            onClick={() => setSelectedSign(sign.name)}
            className={`flex flex-col items-center p-3 rounded-xl border transition-all active:scale-95 ${
              selectedSign === sign.name
                ? 'bg-amber-600/20 border-amber-500 shadow-[0_0_15px_rgba(245,158,11,0.2)]'
                : 'bg-slate-800/40 border-slate-700 hover:border-slate-500'
            }`}
          >
            <span className="text-3xl mb-1">{sign.symbol}</span>
            <span className="text-xs font-semibold uppercase tracking-wider text-slate-300">{sign.name}</span>
            <span className="text-[10px] text-slate-500 italic">{sign.moonSign}</span>
          </button>
        ))}
      </div>

      <div className="flex justify-center gap-2">
        {(['daily', 'weekly', 'monthly'] as Timeframe[]).map((tf) => (
          <button
            key={tf}
            onClick={() => setTimeframe(tf)}
            className={`px-6 py-2 rounded-full text-sm font-medium border capitalize transition-all ${
              timeframe === tf
                ? 'bg-slate-200 text-slate-900 border-white'
                : 'bg-transparent text-slate-400 border-slate-700 hover:border-slate-500'
            }`}
          >
            {tf}
          </button>
        ))}
      </div>

      {loading ? (
        <div className="flex flex-col items-center justify-center py-20 space-y-4">
          <div className="w-12 h-12 border-4 border-amber-500/30 border-t-amber-500 rounded-full animate-spin"></div>
          <p className="text-slate-400 font-cinzel animate-pulse">Consulting the celestial bodies...</p>
        </div>
      ) : prediction ? (
        <div id="horoscope-content" className="space-y-6">
          <div className="flex justify-between items-center no-print px-2">
            <h2 className="text-2xl font-cinzel text-amber-200">{selectedSign} {timeframe} Forecast</h2>
            <button 
              onClick={downloadPDF}
              disabled={exporting}
              className="bg-slate-700/50 hover:bg-slate-600 text-white text-xs px-4 py-2 rounded-lg flex items-center gap-2 transition-colors border border-slate-600 disabled:opacity-50"
            >
              {exporting ? 'Generating...' : <><span>📥</span> Save Forecast</>}
            </button>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="col-span-1 md:col-span-2 bg-slate-800/50 p-6 rounded-2xl border border-slate-700 shadow-xl">
              <h3 className="text-xl font-cinzel text-amber-400 mb-3 flex items-center gap-2">
                <span>✨</span> Overview
              </h3>
              <p className="text-slate-300 leading-relaxed text-lg italic">"{prediction.overview}"</p>
            </div>

            <PredictionCard title="💼 Career & Finance" content={prediction.career + " " + prediction.finance} icon="💰" />
            <PredictionCard title="🌿 Health & Wellness" content={prediction.health} icon="🧘" />
            <PredictionCard title="💞 Love & Relations" content={prediction.relationships} icon="💖" />
            <PredictionCard title="✨ Spirituality" content={prediction.spirituality} icon="🕉️" />

            <div className="col-span-1 md:col-span-2 flex flex-wrap gap-4 justify-center bg-amber-900/10 p-4 rounded-xl border border-amber-900/30">
              <div className="flex items-center gap-2">
                <span className="text-slate-400 text-sm">Lucky Color:</span>
                <span className="font-bold text-amber-500">{prediction.luckyColor}</span>
              </div>
              <div className="w-px h-4 bg-slate-700"></div>
              <div className="flex items-center gap-2">
                <span className="text-slate-400 text-sm">Lucky Number:</span>
                <span className="font-bold text-amber-500">{prediction.luckyNumber}</span>
              </div>
            </div>
          </div>
        </div>
      ) : null}
    </div>
  );
};

const PredictionCard: React.FC<{ title: string; content: string; icon: string }> = ({ title, content, icon }) => (
  <div className="bg-slate-800/30 p-5 rounded-2xl border border-slate-800 hover:border-slate-700 transition-colors shadow-inner">
