  const cacheKey = StorageService.getKeys.horoscope(sign, timeframe, language);
  const cached = StorageService.get<any>(cacheKey);
  if (cached) return cached;

  const result = await withRetry(async () => {
    const ai = new GoogleGenAI({ apiKey: getSafeApiKey() });
    const prompt = `As a Vedic Astrologer, date ${getCurrentDate()}. ${timeframe} for Moon Sign ${sign} in ${language} for year 2026. JSON: overview, career, health, relationships, finance, spirituality, luckyColor, luckyNumber.`;
    const response = await ai.models.generateContent({
