          {Object.entries(data).map(([house, planets]) => {
            const h = parseInt(house);
            const coord = houseCoords[h];
            if (!coord) return null;

            return (
              <g key={`house-${h}`}>
                {planets.map((p, idx) => {
                  // Offset planets if multiple exist in one house
                  const offsetX = (idx % 2 === 0 ? -1 : 1) * 18 * Math.floor(idx / 2 + 0.5);
                  const offsetY = Math.floor(idx / 2) * 15;

                  return (
                    <text
                      key={`planet-${h}-${idx}`}
