import React, { useState, useRef, useEffect } from 'react';
import { BirthDetails, Language, ChatMessage, KundaliResponse } from '../types';
import { getCoordinates, getKundaliAnalysis, askKundaliQuestion } from '../services/geminiService';
import KundaliChart from './KundaliChart';
import ReactMarkdown from 'https://esm.sh/react-markdown';
import jsPDF from 'jspdf';
import html2canvas from 'html2canvas';

interface KundaliViewProps {
  language: Language;
}

const KundaliView: React.FC<KundaliViewProps> = ({ language }) => {
  const [details, setDetails] = useState<BirthDetails>({
    name: '',
    dob: '',
    tob: '',
    location: '',
  });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [exporting, setExporting] = useState(false);
  const [analysis, setAnalysis] = useState<KundaliResponse | null>(null);

  const [chatHistory, setChatHistory] = useState<ChatMessage[]>([]);
  const [userQuery, setUserQuery] = useState('');
  const [chatLoading, setChatLoading] = useState(false);
  const chatEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [chatHistory, chatLoading]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);
    setChatHistory([]);
    try {
      const locationData = await getCoordinates(details.location);
      const enrichedDetails = {
        ...details,
        latitude: locationData.lat,
        longitude: locationData.lng,
      };
      const result = await getKundaliAnalysis(enrichedDetails, language);
      setAnalysis(result);
    } catch (err: any) {
      console.error(err);
      setError(err.message || "Celestial connection failed. Please check your inputs.");
    } finally {
      setLoading(false);
    }
  };

  const handleAskQuestion = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!userQuery.trim() || !analysis || chatLoading) return;

    const currentQuery = userQuery;
    setUserQuery('');
    setChatHistory(prev => [...prev, { role: 'user', text: currentQuery }]);
    setChatLoading(true);

    try {
      const response = await askKundaliQuestion(currentQuery, analysis.report, chatHistory, language);
      setChatHistory(prev => [...prev, { role: 'model', text: response }]);
    } catch (error) {
      console.error(error);
      setChatHistory(prev => [...prev, { role: 'model', text: "The heavens are clouded." }]);
    } finally {
      setChatLoading(false);
    }
  };

  const downloadPDF = async () => {
    const element = document.getElementById('kundali-report');
    if (!element || exporting) return;

    setExporting(true);
    try {
      const canvas = await html2canvas(element, {
        scale: 2,
        backgroundColor: '#010204',
        useCORS: true,
      });

      const imgData = canvas.toDataURL('image/png');
      const pdf = new jsPDF('p', 'mm', 'a4');
      const pageWidth = pdf.internal.pageSize.getWidth();
      const pageHeight = pdf.internal.pageSize.getHeight();
      const imgWidth = pageWidth;
      const imgHeight = (canvas.height * imgWidth) / canvas.width;

      let heightLeft = imgHeight;
      let position = 0;

      pdf.addImage(imgData, 'PNG', 0, position, imgWidth, imgHeight);
      heightLeft -= pageHeight;

      while (heightLeft > 0) {
        position -= pageHeight;
        pdf.addPage();
        pdf.addImage(imgData, 'PNG', 0, position, imgWidth, imgHeight);
        heightLeft -= pageHeight;
      }

      pdf.save(`Kundali_Report_2026_${details.name}.pdf`);
    } catch (err) {
      console.error("PDF failed", err);
    } finally {
      setExporting(false);
    }
  };

  return (
    <div className="space-y-8 max-w-5xl mx-auto pb-20 px-2 md:px-0">
      {!analysis && !loading && (
        <section className="mirror-card p-6 md:p-12 rounded-3xl animate-in fade-in slide-in-from-bottom-4 duration-700">
          <div className="mb-10 text-center">
            <h2 className="text-3xl md:text-5xl font-cinzel text-amber-100 mb-4 tracking-tight">Divine Chart Analysis</h2>
            <p className="text-slate-400 max-w-xl mx-auto text-sm md:text-base">Reveal your celestial blueprint and 2026 transits.</p>
          </div>

          <form onSubmit={handleSubmit} className="space-y-8 max-w-3xl mx-auto">
            {error && (
              <div className="p-4 bg-red-500/10 border border-red-500/30 rounded-2xl text-red-200 text-xs text-center">
                {error}
              </div>
            )}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6 md:gap-8">
              <InputField label="Name" value={details.name} onChange={(v) => setDetails({ ...details, name: v })} />
              <InputField label="City" value={details.location} onChange={(v) => setDetails({ ...details, location: v })} />
              <InputField label="Date" type="date" value={details.dob} onChange={(v) => setDetails({ ...details, dob: v })} />
              <InputField label="Time" type="time" value={details.tob} onChange={(v) => setDetails({ ...details, tob: v })} />
            </div>
            <button disabled={loading} className="w-full glossy-button text-white font-bold py-4 rounded-2xl text-lg tracking-widest uppercase font-cinzel">
              Generate Divine Chart
            </button>
          </form>
        </section>
      )}

      {loading && (
        <div className="flex flex-col items-center justify-center py-24 space-y-8">
          <div className="w-24 h-24 border-4 border-amber-500/10 border-t-amber-500 rounded-full animate-spin"></div>
          <p className="text-2xl font-cinzel text-amber-200">Decoding the Astral Plane...</p>
        </div>
      )}

      {analysis && !loading && (
        <div className="space-y-12 animate-in fade-in duration-1000">
          <div id="kundali-report" className="bg-[#010204] rounded-[40px] border border-amber-500/10 overflow-hidden">
            <div className="p-6 md:p-10 border-b border-white/10 flex flex-col md:flex-row justify-between items-center gap-6">
              <div>
                <h2 className="text-3xl font-cinzel text-amber-400">{details.name}'s Soul Reflection</h2>
                <div className="flex gap-2 mt-2 text-[10px] text-slate-500 font-bold uppercase tracking-widest">
                  <span>{details.dob}</span> <span>•</span> <span>{details.location}</span>
                </div>
              </div>
              <button onClick={downloadPDF} disabled={exporting} className="bg-white/10 text-white text-[10px] px-6 py-2.5 rounded-full border border-white/10 no-print">
                {exporting ? 'Wait...' : 'Save Insights'}
              </button>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 p-6 md:p-10">
              <div className="lg:col-span-5 flex flex-col gap-6">
                <KundaliChart data={analysis.chart} />
              </div>
              <div className="lg:col-span-7 prose prose-invert prose-amber max-w-none">
                <ReactMarkdown>{analysis.report}</ReactMarkdown>
              </div>
            </div>
          </div>

          <section className="mirror-card rounded-[40px] p-6 md:p-10 space-y-6 no-print">
            <h3 className="text-xl font-cinzel text-amber-200">Consult the Stars</h3>
            <div className="max-h-[400px] overflow-y-auto space-y-4 pr-2 no-scrollbar">
              {chatHistory.map((msg, idx) => (
                <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                  <div className={`max-w-[80%] p-4 rounded-2xl text-sm ${msg.role === 'user' ? 'bg-amber-600/20 border border-amber-500/30 text-amber-50' : 'bg-white/5 border border-white/10 text-slate-300'}`}>
                    {msg.text}
                  </div>
                </div>
              ))}
              {chatLoading && <div className="text-amber-500/50 text-[10px] animate-pulse">Calculating...</div>}
              <div ref={chatEndRef} />
            </div>
            <form onSubmit={handleAskQuestion} className="flex gap-2">
              <input value={userQuery} onChange={(e) => setUserQuery(e.target.value)} type="text" placeholder="Ask about wealth, health, or career..." className="flex-1 bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-sm focus:ring-1 focus:ring-amber-500 outline-none text-white" />
              <button disabled={chatLoading} className="bg-amber-500 text-slate-900 font-black px-6 rounded-xl text-xs uppercase">Query</button>
            </form>
          </section>

          <button onClick={() => setAnalysis(null)} className="text-slate-500 hover:text-amber-500 mx-auto block no-print text-[10px] font-black uppercase tracking-widest">
            Perform New Analysis
          </button>
        </div>
      )}
    </div>
  );
};

const InputField = ({ label, value, onChange, type = 'text' }: any) => (
  <div className="space-y-2">
    <label className="text-[10px] font-black text-amber-500/60 uppercase tracking-widest">{label}</label>
    <input required type={type} className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-white focus:ring-1 focus:ring-amber-500 outline-none" value={value} onChange={(e) => onChange(e.target.value)} />
