// Fixed type declaration for global Window object to resolve compilation errors
declare global {
  interface AIStudio {
    hasSelectedApiKey: () => Promise<boolean>;
    openSelectKey: () => Promise<void>;
  }
  interface Window {
    aistudio?: AIStudio;
  }
}

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('horoscope');
  const [language, setLanguage] = useState<Language>('English');
  const [isKeySelected, setIsKeySelected] = useState<boolean | null>(null);

  useEffect(() => {
    const checkKey = async () => {
      // Safety timeout: If checking takes too long, just proceed to rendering
      const timeout = setTimeout(() => {
        if (isKeySelected === null) {
          console.warn("Key check timed out, proceeding to app.");
          setIsKeySelected(true);
        }
      }, 3000);

      try {
        if (!window.aistudio || !window.aistudio.hasSelectedApiKey) {
          setIsKeySelected(true);
          clearTimeout(timeout);
          return;
        }
        const hasKey = await window.aistudio.hasSelectedApiKey();
        setIsKeySelected(hasKey);
      } catch (err) {
        console.error("Failed to check AI Studio key state:", err);
        setIsKeySelected(true); // Fallback to avoid blank screen
      } finally {
        clearTimeout(timeout);
      }
    };
    checkKey();
  }, []);

  // Background Update Logic
  useEffect(() => {
    if (isKeySelected === false) return;

    const syncData = async () => {
      const prefSign = StorageService.getUserSign() || ZODIAC_SIGNS[0].name;
      try {
        await getHoroscope(prefSign, 'daily', language);
      } catch (e) {
        console.warn("Background sync failed", e);
      }
    };

    syncData();
  }, [language, isKeySelected]);

  const handleConnectKey = async () => {
    if (window.aistudio) {
      try {
        await window.aistudio.openSelectKey();
      } catch (e) {
        console.error("Failed to open key selector", e);
      }
    }
    setIsKeySelected(true);
  };

  // While waiting for initial check, the HTML loader is visible.
  // Once state changes from null, React replaces it.
  if (isKeySelected === null) return null;

  if (isKeySelected === false) {
    return (
      <div className="min-h-screen flex items-center justify-center p-4 bg-[#010204]">
        <div className="mirror-card p-8 md:p-12 rounded-[40px] max-w-xl w-full text-center space-y-8 animate-in fade-in zoom-in-95 duration-700 border-amber-500/20 shadow-[0_0_100px_rgba(251,191,36,0.1)]">
