            <div className="text-6xl animate-pulse">✨</div>
            <h1 className="text-4xl font-cinzel text-amber-200">Celestial Gateway</h1>
            <p className="text-slate-400 text-sm md:text-base leading-relaxed">
              To provide high-precision Vedic predictions and planetary transits, you must connect your own Google Cloud API project.
            </p>
          </div>

          <div className="bg-white/5 p-6 rounded-3xl border border-white/10 space-y-4 text-left">
             <div className="flex items-start gap-3">
               <span className="text-amber-500 mt-1">✓</span>
               <p className="text-xs text-slate-300">Enables high-speed Gemini 3 Pro analysis.</p>
             </div>
             <div className="flex items-start gap-3">
               <span className="text-amber-500 mt-1">✓</span>
               <p className="text-xs text-slate-300">Requires a project with billing enabled.</p>
             </div>
             <a 
               href="https://ai.google.dev/gemini-api/docs/billing" 
               target="_blank" 
               rel="noopener noreferrer"
               className="block text-center text-[10px] text-amber-500/60 uppercase font-black tracking-widest hover:text-amber-400 underline decoration-amber-500/30"
             >
               View Billing Documentation
             </a>
          </div>

          <button 
            onClick={handleConnectKey}
            className="w-full glossy-button text-white font-black py-5 rounded-2xl text-sm tracking-[0.3em] uppercase font-cinzel shadow-2xl"
          >
            Connect to the Cosmos
          </button>

          <p className="text-[10px] text-slate-600 font-medium uppercase tracking-widest">
            Powered by Google AI Studio
          </p>
        </div>
      </div>
    );
  }

  const renderContent = () => {
    switch (activeTab) {
      case 'horoscope':
        return <HoroscopeView language={language} />;
      case 'kundali':
        return <KundaliView language={language} />;
      case 'palmistry':
        return <PalmistryView language={language} />;
      case 'numerology':
        return <NumerologyView language={language} />;
      case 'matchmaking':
        return <MatchmakingView language={language} />;
      default:
        return <HoroscopeView language={language} />;
    }
  };

  return (
    <Layout 
      activeTab={activeTab} 
      setActiveTab={setActiveTab} 
      language={language} 
      setLanguage={setLanguage}
    >
      <div className="max-w-5xl mx-auto">
        {renderContent()}
      </div>
    </Layout>
  );
};

export default App;

